    // Trigger actions when the user enters or exits the geofenced area
    if (position.coords.latitude >= geofence.latitude - geofence.radius &&
        position.coords.latitude <= geofence.latitude + geofence.radius &&
        position.coords.longitude >= geofence.longitude - geofence.radius &&
        position.coords.longitude <= geofence.longitude + geofence.radius) {
        // Send a notification when the user enters the geofenced area
        sendNotification("Welcome to San Francisco!");
    } else {
        // Send a notification when the user exits the geofenced area
        sendNotification("Goodbye San Francisco!");
    }
}, error => {
    console.error("Error:", error);
});

// Send a notification
function sendNotification(message) {
    const notification = new Notification(message);
    notification.show();
}
```

